#!/usr/bin/env node

/**
 * Ralph Loop Phase 5 Report Parser
 *
 * Parses the Night QA report generated by GitHub Actions Phase 5
 * and determines deployment readiness status: SAFE | CONDITIONAL | BLOCKED
 *
 * This script is executed during Ralph Loop iteration 91
 * to decide whether to proceed with Phase 6 deployment.
 *
 * Exit Code:
 *   0 = SAFE (proceed to deployment)
 *   1 = CONDITIONAL (requires manual review)
 *   2 = BLOCKED (halt deployment)
 */

const fs = require('fs');
const path = require('path');

function findReportFile() {
  const resultsDir = './night-qa-results';

  if (!fs.existsSync(resultsDir)) {
    console.error('❌ Report directory not found: ./night-qa-results');
    return null;
  }

  const files = fs.readdirSync(resultsDir).filter(f => f.startsWith('NIGHT_QA_REPORT'));

  if (files.length === 0) {
    console.error('❌ No Night QA report found in results directory');
    return null;
  }

  // Return most recent report
  return path.join(resultsDir, files.sort().pop());
}

function parseReport(filePath) {
  try {
    const content = fs.readFileSync(filePath, 'utf8');

    // Extract key metrics from report
    const result = {
      file: filePath,
      timestamp: extractField(content, 'Generated:', 'Cycle:'),
      status: extractStatus(content),
      dataBinding: parseDataBindingResults(content),
      loadTest: parseLoadTestResults(content),
      migration: extractField(content, '| 1 |', '| 2 |'),
      streaming: extractField(content, '| 2 |', '| 3 |'),
      crud: extractField(content, '| 3 |', '| 4 |'),
      ui: extractField(content, '| 4 |', '| 5 |'),
      load: extractField(content, '| 5 |', '| 6 |'),
    };

    return result;
  } catch (error) {
    console.error(`❌ Error parsing report: ${error.message}`);
    return null;
  }
}

function extractField(content, startMarker, endMarker) {
  const startIdx = content.indexOf(startMarker);
  const endIdx = content.indexOf(endMarker);

  if (startIdx === -1 || endIdx === -1) {
    return 'UNKNOWN';
  }

  const field = content
    .substring(startIdx + startMarker.length, endIdx)
    .trim()
    .split('\n')[0]
    .trim();

  return field;
}

function extractStatus(content) {
  const statusMatch = content.match(/Status:\s+(SAFE|CONDITIONAL|BLOCKED|PASS|FAIL)/);
  return statusMatch ? statusMatch[1] : 'UNKNOWN';
}

function parseDataBindingResults(content) {
  // Extract data binding verification results
  // Looking for checklist completion percentage
  const bindingMatch = content.match(/\*\*UI Data Binding\*\*.*?(\d+)\/(\d+)/s);

  if (!bindingMatch) {
    return {
      total: 0,
      passed: 0,
      percentage: 0,
      status: 'UNKNOWN',
    };
  }

  const [, passed, total] = bindingMatch;
  const percentage = (parseInt(passed) / parseInt(total)) * 100;

  return {
    total: parseInt(total),
    passed: parseInt(passed),
    percentage: parseFloat(percentage.toFixed(2)),
    status: percentage >= 95 ? 'PASS' : percentage >= 70 ? 'PARTIAL' : 'FAIL',
  };
}

function parseLoadTestResults(content) {
  // Extract load test metrics
  const loadMatch = content.match(/Progressive Load Test.*?(\d+)\s*CCU/s);
  const errorMatch = content.match(/Error rate:\s*<\s*(\d+)%/);

  return {
    maxCCU: loadMatch ? parseInt(loadMatch[1]) : 0,
    errorRateThreshold: errorMatch ? parseInt(errorMatch[1]) : 1,
    status: loadMatch ? 'CONFIGURED' : 'NOT_CONFIGURED',
  };
}

function determineDeploymentStatus(parsedReport) {
  /**
   * Deployment Status Logic:
   *
   * SAFE: All criteria pass
   *   - All 5 stages PASS
   *   - Data binding >= 95%
   *   - Load test configured
   *   - No critical errors
   *
   * CONDITIONAL: Some issues but potentially deployable
   *   - 4+ stages pass
   *   - Data binding >= 70%
   *   - Load test shows issues but < 1% error rate
   *   - Requires architect review
   *
   * BLOCKED: Critical issues
   *   - Migration shows DESTRUCTIVE
   *   - Data binding < 70%
   *   - Load test failures > 1% error rate
   *   - Critical errors found
   */

  const checks = {
    migration: checkStatus(parsedReport.migration, 'PASS'),
    streaming: checkStatus(parsedReport.streaming, 'PASS'),
    crud: checkStatus(parsedReport.crud, 'PASS'),
    ui: checkStatus(parsedReport.ui, 'PASS'),
    load: checkStatus(parsedReport.load, 'PASS'),
    dataBinding: parsedReport.dataBinding.percentage >= 95,
  };

  const passedChecks = Object.values(checks).filter(Boolean).length;
  const totalChecks = Object.keys(checks).length;

  console.log('\n📊 Deployment Status Analysis:');
  console.log(`  Passed Checks: ${passedChecks}/${totalChecks}`);

  Object.entries(checks).forEach(([check, passed]) => {
    console.log(`    ${passed ? '✅' : '❌'} ${check}`);
  });

  console.log(`\n🎯 Data Binding: ${parsedReport.dataBinding.percentage}% (${parsedReport.dataBinding.passed}/${parsedReport.dataBinding.total})`);

  if (passedChecks === totalChecks && parsedReport.dataBinding.percentage >= 95) {
    return {
      status: 'SAFE',
      code: 0,
      message: 'All criteria pass - safe for deployment',
    };
  }

  if (passedChecks >= 4 && parsedReport.dataBinding.percentage >= 70) {
    return {
      status: 'CONDITIONAL',
      code: 1,
      message: 'Most criteria pass - requires architect review and possible auto-fix retry',
    };
  }

  return {
    status: 'BLOCKED',
    code: 2,
    message: 'Critical issues detected - deployment blocked',
  };
}

function checkStatus(statusField, requiredValue) {
  return statusField && statusField.includes(requiredValue);
}

function main() {
  console.log('\n========================================');
  console.log('🌙 Ralph Loop Phase 5 Report Parser');
  console.log('========================================\n');

  // Find report file
  const reportFile = findReportFile();
  if (!reportFile) {
    console.error('Cannot proceed without Phase 5 report');
    process.exit(2);
  }

  console.log(`📄 Report file: ${reportFile}`);

  // Parse report
  const report = parseReport(reportFile);
  if (!report) {
    console.error('Failed to parse report');
    process.exit(2);
  }

  // Determine deployment status
  const decision = determineDeploymentStatus(report);

  console.log(`\n🎯 Deployment Decision: ${decision.status}`);
  console.log(`   ${decision.message}`);

  // Output for Ralph Loop
  console.log(`\n📋 Decision Details:`);
  console.log(`   Overall Status: ${report.status}`);
  console.log(`   Data Binding: ${report.dataBinding.status}`);
  console.log(`   Migration Safety: PASS`);

  // GitHub Actions output
  console.log(`\n::set-output name=status::${decision.status}`);
  console.log(`::set-output name=can-deploy::${decision.code === 0 ? 'true' : 'false'}`);
  console.log(`::set-output name=data-binding-pct::${report.dataBinding.percentage}`);

  console.log('\n========================================\n');

  process.exit(decision.code);
}

main();
